tmpHtml+='<div class="facto-scanner-detail-grid">';tmpHtml+='<div><strong>Folder:</strong> <span style="font-family:\'SF Mono\', Consolas, monospace;">'+this.escapeHtml(pDS.FolderName)+'</span></div>';tmpHtml+='<div><strong>Status:</strong> '+this.getStatusBadge(pDS.Status)+'</div>';tmpHtml+='<div><strong>Provider:</strong> '+this.escapeHtml(pDS.Provider||'Unknown')+'</div>';tmpHtml+='<div><strong>License:</strong> '+this.escapeHtml(pDS.License||'Unknown')+'</div>';if(pDS.SourceURL){tmpHtml+='<div><strong>Source:</strong> <a href="'+this.escapeHtml(pDS.SourceURL)+'" target="_blank" style="color:var(--facto-brand);">'+this.escapeHtml(pDS.SourceURL.substring(0,60))+'</a></div>';}if(pDS.UpdateFrequency){tmpHtml+='<div><strong>Update Frequency:</strong> '+this.escapeHtml(pDS.UpdateFrequency.substring(0,100))+'</div>';}if(pDS.RecordCount){tmpHtml+='<div><strong>Record Count:</strong> '+this.escapeHtml(pDS.RecordCount.substring(0,100))+'</div>';}if(pDS.IDSource){tmpHtml+='<div><strong>Source ID:</strong> <a href="#/Source/'+pDS.IDSource+'" style="color:var(--facto-brand);">#'+pDS.IDSource+'</a></div>';}if(pDS.IDDataset){tmpHtml+='<div><strong>Dataset ID:</strong> #'+pDS.IDDataset+'</div>';}tmpHtml+='</div>';// Description
