if(pDS.DataFiles&&pDS.DataFiles.length>0){tmpHtml+='<div style="margin-bottom:1em;"><strong>Data Files ('+pDS.DataFiles.length+'):</strong>';tmpHtml+='<table style="margin-top:0.35em;"><thead><tr><th>File</th><th>Format</th><th>Size</th><th>Compressed</th></tr></thead><tbody>';for(let i=0;i<pDS.DataFiles.length&&i<20;i++){let tmpFile=pDS.DataFiles[i];let tmpSize=this.formatSize(tmpFile.Size||0);tmpHtml+='<tr>';tmpHtml+='<td style="font-family:\'SF Mono\', Consolas, monospace; font-size:0.85em;">'+this.escapeHtml(tmpFile.FileName)+'</td>';tmpHtml+='<td><span class="facto-badge facto-badge-primary">'+(tmpFile.Format||'')+'</span></td>';tmpHtml+='<td>'+tmpSize+'</td>';tmpHtml+='<td>'+(tmpFile.Compressed?'Yes':'No')+'</td>';tmpHtml+='</tr>';}tmpHtml+='</tbody></table>';tmpHtml+='</div>';}// Ingestion Plan
